import akka.actor.{Actor, ActorSystem}
import scala.concurrent.duration._

class AccountBalanceActor extends Actor {
  var balance = 0.0

  override def receive: Receive = {
    case Deposit(amount) =>
      balance += amount
      sender() ! BalanceUpdated(balance)

    case Withdraw(amount) if balance >= amount =>
      balance -= amount
      sender() ! BalanceUpdated(balance)

    case _ => // Ignore invalid messages
  }
}

case class Deposit(amount: Double)
case class Withdraw(amount: Double)
case class BalanceUpdated(newBalance: Double)

object AccountBalanceActor {
  def main(args: Array[String]): Unit = {
    val system = ActorSystem("AccountBalanceActor")
    val accountBalanceActor = system.actorOf(Props[AccountBalanceActor])

    // Simulate concurrent transactions
    for (i <- 1 to 10) {
      system.scheduler.scheduleOnce(Duration(0, MILLISECONDS)) {
        accountBalanceActor ! Deposit(100.0)
      }
      system.scheduler.scheduleOnce(Duration(5, MILLISECONDS)) {
        accountBalanceActor ! Withdraw(50.0)
      }
    }

    // Wait for all transactions to complete
    Thread.sleep(10000)

    println("Final balance: " + accountBalanceActor.balance)
  }
}